
class BrowserDetector {
  constructor() {
    this.name = 'other';
    this.version = 0;
    this.os = 'other';
    this.osVersion = 0;
    this.touch = false;
    this.mobile = false;
    this._canvas = null;

    this.init();
  }


  canUse(property) {
    if (!this._canvas) this._canvas = document.createElement('div');
    const style = this._canvas.style;
    const upper = property.charAt(0).toUpperCase() + property.slice(1);
    return property in style || 
           `Moz${upper}` in style || 
           `Webkit${upper}` in style || 
           `O${upper}` in style || 
           `ms${upper}` in style;
  }

  init() {
    const ua = navigator.userAgent;
    
    const browsers = [
      ['firefox', /Firefox\/([0-9\.]+)/],
      ['bb', /BlackBerry.+Version\/([0-9\.]+)/],
      ['bb', /BB[0-9]+.+Version\/([0-9\.]+)/],
      ['opera', /OPR\/([0-9\.]+)/],
      ['opera', /Opera\/([0-9\.]+)/],
      ['edge', /Edge\/([0-9\.]+)/],
      ['safari', /Version\/([0-9\.]+).+Safari/],
      ['chrome', /Chrome\/([0-9\.]+)/],
      ['ie', /MSIE ([0-9]+)/],
      ['ie', /Trident\/.+rv:([0-9]+)/]
    ];

    for (const [name, regex] of browsers) {
      const match = ua.match(regex);
      if (match) {
        this.name = name;
        this.version = parseFloat(match[1]);
        break;
      }
    }

    const systems = [
      ['ios', /([0-9_]+) like Mac OS X/, v => v.replace(/_/g, '.')],
      ['ios', /CPU like Mac OS X/, () => 0],
      ['wp', /Windows Phone ([0-9\.]+)/],
      ['android', /Android ([0-9\.]+)/],
      ['mac', /Macintosh.+Mac OS X ([0-9_]+)/, v => v.replace(/_/g, '.')],
      ['windows', /Windows NT ([0-9\.]+)/],
      ['bb', /BlackBerry.+Version\/([0-9\.]+)/],
      ['linux', /Linux/],
      ['bsd', /BSD/],
      ['unix', /X11/]
    ];

    for (const [os, regex, formatter] of systems) {
      const match = ua.match(regex);
      if (match) {
        this.os = os;
        const rawVersion = match[1] || 0;
        this.osVersion = formatter ? parseFloat(formatter(rawVersion)) : parseFloat(rawVersion);
        break;
      }
    }

    if (this.os === 'mac' && ('ontouchstart' in window)) {
      const isIPadSize = (
        (screen.width === 1024 && screen.height === 1366) ||
        (screen.width === 834 && screen.height === 1112) ||
        (screen.width === 810 && screen.height === 1080) ||
        (screen.width === 768 && screen.height === 1024)
      );
      if (isIPadSize) this.os = 'ios';
    }

    this.touch = (this.os === 'wp') 
      ? (navigator.msMaxTouchPoints > 0) 
      : ('ontouchstart' in window || navigator.maxTouchPoints > 0);

    this.mobile = ['wp', 'android', 'ios', 'bb'].includes(this.os);
  }
}

const browser = new BrowserDetector();
export default browser;
